import React, { useState, useEffect } from "react";
import { UsersIcon, AcademicCapIcon, ChartBarIcon, ArrowDownTrayIcon } from "@heroicons/react/24/outline";
import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, BarChart, Bar, Legend, PieChart, Pie, Cell } from "recharts";

const userGrowthData = [ { month: "Jan", users: 400 }, { month: "Feb", users: 600 }, { month: "Mar", users: 800 }, { month: "Apr", users: 1200 }, { month: "May", users: 1500 }, { month: "Jun", users: 2100 } ];
const quizStatsData = [ { subject: "Math", attempts: 120, avgScore: 85 }, { subject: "Science", attempts: 98, avgScore: 78 }, { subject: "History", attempts: 86, avgScore: 92 }, { subject: "English", attempts: 150, avgScore: 88 } ];
const roleDistribution = [ { name: "Students", value: 1800 }, { name: "Academic Panel", value: 45 }, { name: "Admins", value: 5 } ];
const PIE_COLORS = ["#10b981", "#6366f1", "#ef4444"]; 

export default function AdminReports() {
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const timer = setTimeout(() => setLoading(false), 800);
    return () => clearTimeout(timer);
  }, []);

  if (loading) return <div className="min-h-screen w-[83vw] ml-[17vw] bg-gray-900 flex items-center justify-center text-white"><p className="animate-pulse">Loading Reports...</p></div>;

  return (
    <div className="min-h-screen w-[83vw] ml-[17vw] bg-gradient-to-br from-slate-900 via-gray-900 to-slate-800 p-8 text-white">
      <div className="flex justify-between items-center mb-8 mt-10">
        <div>
          <h1 className="text-3xl font-bold">Platform Analytics</h1>
          <p className="text-gray-400 mt-1">Real-time overview of Smart Learning metrics</p>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
        <StatCard title="Total Users" value="2,100" trend="+12% this month" icon={<UsersIcon className="w-8 h-8 text-blue-400" />} color="border-blue-500/30" />
        <StatCard title="Quizzes Attempted" value="14,320" trend="+8% this week" icon={<AcademicCapIcon className="w-8 h-8 text-green-400" />} color="border-green-500/30" />
        <StatCard title="Average Score" value="84.5%" trend="+2.1% overall" icon={<ChartBarIcon className="w-8 h-8 text-purple-400" />} color="border-purple-500/30" />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-8">
        <div className="bg-white/5 backdrop-blur-lg border border-white/10 p-6 rounded-2xl shadow-xl">
          <h3 className="text-lg font-semibold mb-4 text-indigo-300">User Growth</h3>
          <div className="h-72">
            <ResponsiveContainer width="100%" height="100%">
              <AreaChart data={userGrowthData}>
                <CartesianGrid strokeDasharray="3 3" stroke="#ffffff1a" />
                <XAxis dataKey="month" stroke="#9ca3af" />
                <YAxis stroke="#9ca3af" />
                <Tooltip contentStyle={{ backgroundColor: "#1e293b", border: "none" }} itemStyle={{ color: "#fff" }} />
                <Area type="monotone" dataKey="users" stroke="#818cf8" fill="#6366f1" fillOpacity={0.4} />
              </AreaChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-white/5 backdrop-blur-lg border border-white/10 p-6 rounded-2xl shadow-xl">
          <h3 className="text-lg font-semibold mb-4 text-indigo-300">Quiz Engagement</h3>
          <div className="h-72">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={quizStatsData}>
                <CartesianGrid strokeDasharray="3 3" stroke="#ffffff1a" />
                <XAxis dataKey="subject" stroke="#9ca3af" />
                <YAxis stroke="#9ca3af" />
                <Tooltip contentStyle={{ backgroundColor: "#1e293b", border: "none" }} />
                <Bar dataKey="attempts" fill="#34d399" radius={[4, 4, 0, 0]} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>
      </div>
    </div>
  );
}

function StatCard({ title, value, trend, icon, color }) {
  return (
    <div className={`bg-white/5 backdrop-blur-lg border ${color} p-6 rounded-2xl shadow-xl flex items-center justify-between`}>
      <div><p className="text-gray-400 text-sm">{title}</p><h3 className="text-3xl font-bold mt-1">{value}</h3><p className="text-sm text-indigo-300 mt-2">{trend}</p></div>
      <div className="p-4 bg-white/5 rounded-xl border border-white/10">{icon}</div>
    </div>
  );
}
